), src_norm AS ( SELECT src.external_ref, src.legal_name, src.trade_name, src.tax_id, src.metadata, CASE WHEN src.tax_id IS NULL OR src.tax_id = '' THEN NULL WHEN row_number() OVER (PARTITION BY src.tax_id ORDER BY src.external_ref) > 1 THEN NULL WHEN EXISTS (  SELECT 1 FROM public.customers cx   WHERE cx.tax_id = src.tax_id     AND (cx.source_system <> 'bling' OR cx.external_ref <> src.external_ref)) THEN NULL ELSE src.tax_id END AS tax_id_safe FROM src)
INSERT INTO public.customers (legal_name, trade_name, tax_id, status, notes, metadata, source_system, external_ref) SELECT src_norm.legal_name, src_norm.trade_name, src_norm.tax_id_safe, 'active', 'Imported from Bling contas_receber', src_norm.metadata, 'bling', src_norm.external_ref FROM src_norm
ON CONFLICT (source_system, external_ref) DO UPDATE SET legal_name = EXCLUDED.legal_name, trade_name = EXCLUDED.trade_name, tax_id = COALESCE(EXCLUDED.tax_id, public.customers.tax_id), status = 'active', metadata = COALESCE(public.customers.metadata, '{}'::jsonb) || EXCLUDED.metadata, updated_at = now();

