  SELECT id FROM public.financial_categories WHERE code = 'BLING_AR_IMPORT' LIMIT 1
)
INSERT INTO public.accounts_receivable (customer_id, category_id, description, invoice_number, issue_date, due_date, amount, currency_code, status, notes, metadata, source_system, external_ref)
SELECT c.id, cat.id, src.description, src.document_number, LEAST(src.issue_date::date, src.due_date::date), GREATEST(src.issue_date::date, src.due_date::date), src.amount::numeric(14,2), 'BRL', src.status::receivable_status, 'Imported from Bling contas_receber', src.metadata, 'bling', src.external_ref FROM src JOIN public.customers c ON c.source_system = 'bling' AND c.external_ref = src.customer_external_ref CROSS JOIN cat ON CONFLICT (source_system, external_ref) DO UPDATE SET customer_id = EXCLUDED.customer_id, category_id = EXCLUDED.category_id, description = EXCLUDED.description, invoice_number = EXCLUDED.invoice_number, issue_date = EXCLUDED.issue_date, due_date = EXCLUDED.due_date, amount = EXCLUDED.amount, status = EXCLUDED.status, metadata = COALESCE(public.accounts_receivable.metadata, '{}'::jsonb) || EXCLUDED.metadata, updated_at = now();

